import { HttpEventType } from '@angular/common/http';
import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { ResumeResponse } from '../../../core/models/resume.model';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-upload-resume',
  templateUrl: './upload-resume.component.html'
})
export class UploadResumeComponent {
  selectedFile: File | null = null;
  uploadProgress = 0;
  uploading = false;
  error = '';

  constructor(
    private readonly resumeService: ResumeService,
    private readonly router: Router
  ) {
  }

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.selectedFile = input.files?.[0] ?? null;
    this.error = '';
  }

  upload(): void {
    if (!this.selectedFile) {
      this.error = 'Please choose a PDF resume first.';
      return;
    }

    this.uploading = true;
    this.uploadProgress = 0;
    this.error = '';

    this.resumeService.uploadResumeWithProgress(this.selectedFile).subscribe({
      next: (event) => {
        if (event.type === HttpEventType.UploadProgress && event.total) {
          this.uploadProgress = Math.round((event.loaded / event.total) * 100);
        }

        if (event.type === HttpEventType.Response) {
          const resume = event.body as ResumeResponse;
          this.router.navigate(['/resume', resume.id, 'analysis']);
        }
      },
      error: (error: { error?: { message?: string } }) => {
        this.uploading = false;
        this.error = error.error?.message ?? 'Resume upload failed.';
      }
    });
  }
}
<div class="mx-auto max-w-5xl space-y-6">
  <div class="shell-card p-8">
    <p class="eyebrow">Choose Your Path</p>
    <h2 class="section-title mt-3 text-4xl text-[#17172b]">Start with your existing resume or build a new one.</h2>
    <p class="mt-4 max-w-2xl text-base leading-7 text-[#667085]">
      This screen now works as the guided entry point for the upload flow. If you already have a PDF, upload it below. If not, switch to the builder and create from a template.
    </p>

    <div class="mt-8 grid gap-4 md:grid-cols-2">
      <article class="soft-card p-6">
        <p class="text-lg font-bold text-[#17172b]">Upload Existing Resume</p>
        <p class="mt-3 text-sm leading-6 text-[#667085]">Use your current PDF to get ATS scoring, keyword suggestions, and role matching.</p>
        <div class="mt-5 rounded-[24px] border border-dashed border-[#cfd5f4] bg-white p-5">
          <input type="file" accept=".pdf,application/pdf" (change)="onFileSelected($event)" class="field">
          <p class="mt-4 text-sm text-[#667085]">
            Selected: <span class="font-semibold text-[#17172b]">{{ selectedFile?.name || 'No file selected' }}</span>
          </p>
        </div>
      </article>

      <article class="soft-card p-6">
        <p class="text-lg font-bold text-[#17172b]">Create New Resume</p>
        <p class="mt-3 text-sm leading-6 text-[#667085]">Start from a curated template, edit section by section, and preview before download.</p>
        <div class="mt-5 rounded-[24px] bg-[#17172b] p-5 text-white">
          <p class="text-sm text-white/65">Builder flow</p>
          <div class="mt-4 space-y-3 text-sm">
            <div class="rounded-2xl bg-white/8 px-4 py-3">1. Pick template</div>
            <div class="rounded-2xl bg-white/8 px-4 py-3">2. Fill profile and sections</div>
            <div class="rounded-2xl bg-white/8 px-4 py-3">3. Preview and download</div>
          </div>
          <a routerLink="/resume-builder/templates" class="mt-5 inline-flex rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-[#17172b]">Create resume</a>
        </div>
      </article>
    </div>

    <div *ngIf="uploading" class="mt-6">
      <div class="h-3 overflow-hidden rounded-full bg-[#eceeff]">
        <div class="h-full rounded-full bg-gradient-to-r from-[#5b5cf0] to-[#7c4dff] transition-all" [style.width.%]="uploadProgress"></div>
      </div>
      <p class="mt-3 text-sm font-semibold text-[#667085]">Uploading... {{ uploadProgress }}%</p>
    </div>

    <p *ngIf="error" class="mt-4 rounded-2xl bg-[#fff1f1] px-4 py-3 text-sm font-medium text-[#ef4444]">{{ error }}</p>

    <div class="mt-8 flex gap-3">
      <button class="btn-primary" (click)="upload()" [disabled]="uploading">Upload Resume</button>
      <a routerLink="/dashboard" class="btn-secondary">Back to Dashboard</a>
    </div>
  </div>
</div>
